"use client"

import { useContext } from "react"
import { ProfileContext } from "../../context/profile/ProfileContext"
import { AlertContext } from "../../context/alert/AlertContext"

const PlatformList = ({ platforms }) => {
  const { deletePlatform } = useContext(ProfileContext)
  const { setAlert } = useContext(AlertContext)

  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this platform?")) {
      const result = await deletePlatform(id)

      if (result.success) {
        setAlert(result.msg, "success")
      } else {
        setAlert(result.msg, "danger")
      }
    }
  }

  if (!platforms || platforms.length === 0) {
    return (
      <div className="bg-white p-4 rounded-lg shadow-md">
        <p>No platforms added yet. Add a platform to get started.</p>
      </div>
    )
  }

  return (
    <div className="bg-white p-4 rounded-lg shadow-md">
      <table className="min-w-full">
        <thead>
          <tr>
            <th className="text-left py-2">Platform</th>
            <th className="text-left py-2">Username</th>
            <th className="text-left py-2">URL</th>
            <th className="text-left py-2">Actions</th>
          </tr>
        </thead>
        <tbody>
          {platforms.map((platform) => (
            <tr key={platform._id} className="border-t">
              <td className="py-2">{platform.name}</td>
              <td className="py-2">{platform.username}</td>
              <td className="py-2">
                {platform.url && (
                  <a
                    href={platform.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-blue-600 hover:underline"
                  >
                    Visit
                  </a>
                )}
              </td>
              <td className="py-2">
                <button onClick={() => handleDelete(platform._id)} className="text-red-600 hover:text-red-800">
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}

export default PlatformList
